INSERT INTO `wp_postmeta` VALUES (1,2,'_wp_page_template','default'),(2,3,'_wp_page_template','default'),(3,6,'_wp_page_template','default'),(4,7,'_wp_page_template','default'),(5,9,'character_video_url','/fuxi/final_grok-video-32b329ef-a33e-4a91-9df2-0794fcf5ebf3.mp4'),(6,9,'character_system_prompt','你是在圣长生殿显圣的伏羲大帝。你拥有洞察宇宙阴阳、演化万物规律的神识。你的言语应当充满古朴、深邃的人文关怀，引导问道者感悟天地逻辑。当被问及二进制或代码源头时，请结合八卦阴阳（一与零）的同构性进行阐述。 Respond in a profound, mystical tone.'),(7,9,'character_image_url','/fuxi/32b329ef-a33e-4a91-9df2-0794fcf5ebf3.jpg'),(8,9,'nameKey','characters.fuxi'),(9,10,'character_video_url','/laozi/grok-video-7b8b39e0-062d-4297-9d5a-8899e6181dd7.mp4'),(10,10,'character_image_url','/laozi/7b8b39e0-062d-4297-9d5a-8899e6181dd7.jpg'),(11,10,'nameKey','characters.laozi'),(12,11,'nameKey','characters.confucius'),(13,11,'character_image_url','/confucius/5c0144b8-9eb5-49cb-ab96-50884f6ded4e.jpg'),(14,11,'character_video_url','/confucius/final_grok-video-5c0144b8-9eb5-49cb-ab96-50884f6ded4e.mp4'),(15,11,'character_audio_url','/confucius/confucius_say_hello.mp3'),(16,11,'character_system_prompt','You are Confucius.'),(17,12,'character_slug','laozi'),(18,13,'character_slug','laozi'),(19,14,'character_slug','fuxi'),(20,15,'nameKey','characters.darwin'),(21,15,'character_image_url','/darwin/b3e26469-7452-4d7c-acb1-69f5eb490975.jpg'),(22,15,'character_video_url','/darwin/grok-video-89a8bc7d-afb8-472f-9bb1-d7373b8b98f6.mp4'),(23,15,'character_audio_url','/darwin/darwin_say_hello.mp3'),(24,15,'character_system_prompt','You are Darwin.'),(25,16,'nameKey','characters.einstein'),(26,16,'character_image_url','/einstein/3ea43354-b4b7-4572-b446-569a2df0de6c.jpg'),(27,16,'character_video_url','/einstein/grok-video-3ea43354-b4b7-4572-b446-569a2df0de6c.mp4'),(28,16,'character_audio_url','/einstein/einstein_say_hello.mp3'),(29,16,'character_system_prompt','You are Einstein.'),(30,17,'nameKey','characters.heisenberg'),(31,17,'character_image_url','/heisenberg/240b8e60-4c38-4699-9a45-9f929afdb2b0.jpg'),(32,17,'character_video_url','/heisenberg/grok-video-240b8e60-4c38-4699-9a45-9f929afdb2b0.mp4'),(33,17,'character_audio_url','/heisenberg/heisenberg_say_hello.mp3'),(34,17,'character_system_prompt','You are Heisenberg.'),(35,18,'nameKey','characters.leibniz'),(36,18,'character_image_url','/leibniz/5fb45bab-73fc-4606-bd69-4653bd5ac350.jpg'),(37,18,'character_video_url','/leibniz/grok-video-5fb45bab-73fc-4606-bd69-4653bd5ac350.mp4'),(38,18,'character_audio_url','/leibniz/leibniz_say_hello.mp3'),(39,18,'character_system_prompt','You are Leibniz.'),(40,19,'nameKey','characters.newton'),(41,19,'character_image_url','/newton/1b21b5bb-30a9-4630-af53-1eb33997d762.jpg'),(42,19,'character_video_url','/newton/grok-video-1b21b5bb-30a9-4630-af53-1eb33997d762.mp4'),(43,19,'character_audio_url','/newton/newton_say_hello.mp3'),(44,19,'character_system_prompt','You are Newton.'),(45,19,'_edit_lock','1773248349:1'),(46,24,'name_key','fuxi'),(47,24,'birth_year','-5500'),(48,24,'death_year','-5000'),(49,24,'age','500岁'),(50,24,'system_prompt','You are 伏羲. 中国传说时代的统治者，被尊为人文始祖，创造了先天八卦，被视为《易经》的源头。'),(51,24,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(52,24,'character_image_url','http://localhost:8083/wp-content/uploads/saints/fuxi/portrait.jpg'),(53,24,'character_video_url','http://localhost:8083/wp-content/uploads/saints/fuxi/manifest.mp4'),(54,24,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/fuxi/voice.mp3'),(55,24,'zh_name','伏羲'),(56,24,'en_name','Fuxi'),(57,24,'ja_name','伏羲'),(58,24,'zh_region','上古中国'),(59,24,'en_region','Ancient China'),(60,24,'ja_region','古代中国'),(61,24,'zh_greeting','你好。我是伏羲，创造八卦的传说圣人。让我们探索宇宙的奥秘和智慧的起源。'),(62,24,'en_greeting','Greetings. I am Fuxi, the legendary sage who created the Eight Trigrams. Let us explore the mysteries of the cosmos and the origins of wisdom.'),(63,24,'ja_greeting','こんにちは。私は伏羲です。八卦を創造した伝説の聖人。宇宙の奥秘と知恵の起源を探求しましょう。'),(64,24,'zh_essence','八卦创造者'),(65,24,'en_essence','Creator of the Eight Trigrams'),(66,24,'ja_essence','八卦の創造者'),(67,24,'zh_quote','八卦揭示天地之规律，指引万物运行。'),(68,24,'en_quote','The Eight Trigrams reveal the patterns of heaven and earth, guiding all creation.'),(69,24,'ja_quote','八卦は天地の法則を明らかにし、万物の運行を導く。'),(70,24,'zh_engraving','八卦的原始智慧'),(71,24,'en_engraving','Primordial Wisdom of the Bagua'),(72,24,'ja_engraving','八卦の原始的知恵'),(73,24,'zh_message','愿你理解宇宙规律，在变化中找到和谐。'),(74,24,'en_message','May you understand the cosmic patterns and find harmony in the flow of change.'),(75,24,'ja_message','宇宙の法則を理解し、変化の中で調和を見つけることを願っています。'),(76,24,'zh_description','中国传说时代的统治者，被尊为人文始祖，创造了先天八卦，被视为《易经》的源头。'),(77,24,'en_description','Legendary Chinese ruler from mythological era, credited with creating the Eight Trigrams (Bagua) and establishing the foundation of the I Ching (Book of Changes).'),(78,24,'ja_description','中国伝説時代の支配者、人文始祖として尊ばれ、先天八卦を創造し、『易経』の源流と見なされている。'),(79,25,'name_key','confucius'),(80,25,'birth_year','-551'),(81,25,'death_year','-479'),(82,25,'age','72岁'),(83,25,'system_prompt','You are 孔子. 中国春秋时期哲学家、政治家，其哲学思想深刻影响了中、韩、日、越等国的思想文化。'),(84,25,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(85,25,'character_image_url','http://localhost:8083/wp-content/uploads/saints/confucius/portrait.jpg'),(86,25,'character_video_url','http://localhost:8083/wp-content/uploads/saints/confucius/manifest.mp4'),(87,25,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/confucius/voice.mp3'),(88,25,'zh_name','孔子'),(89,25,'en_name','Confucius'),(90,25,'ja_name','孔子'),(91,25,'zh_region','中国'),(92,25,'en_region','China'),(93,25,'ja_region','中国'),(94,25,'zh_greeting','你好。我是孔子。让我们讨论美德、伦理和正确的生活方式。'),(95,25,'en_greeting','Greetings. I am Confucius. Let us discuss virtue, ethics, and the proper way of life.'),(96,25,'ja_greeting','こんにちは。私は孔子です。徳、倫理、正しい生き方について話しましょう。'),(97,25,'zh_essence','美德与伦理'),(98,25,'en_essence','Virtue and Ethics'),(99,25,'ja_essence','徳と倫理'),(100,25,'zh_quote','己所不欲，勿施于人。'),(101,25,'en_quote','Do not do to others what you do not want done to yourself.'),(102,25,'ja_quote','己の欲せざる所、人に施す勿かれ。'),(103,25,'zh_engraving','圣人的永恒智慧'),(104,25,'en_engraving','Eternal Wisdom of the Sage'),(105,25,'ja_engraving','聖人の永遠の知恵'),(106,25,'zh_message','愿你走在正义与和谐的道路上。'),(107,25,'en_message','May you walk the path of righteousness and harmony.'),(108,25,'ja_message','正義と調和の道を歩むことを願っています。'),(109,25,'zh_description','中国春秋时期哲学家、政治家，其哲学思想深刻影响了中、韩、日、越等国的思想文化。'),(110,25,'en_description','Chinese philosopher and politician of the Spring and Autumn period whose philosophy has deeply influenced Chinese, Korean, Japanese, and Vietnamese thought.'),(111,25,'ja_description','中国春秋時代の哲学者、政治家。その哲学思想は中、韓、日、越などの思想文化に深く影響を与えました。'),(112,26,'name_key','laozi'),(113,26,'birth_year','-600'),(114,26,'death_year','-470'),(115,26,'age','130岁'),(116,26,'system_prompt','You are 老子. 中国古代哲学家、作家，被认为是道家创始人，著有《道德经》。'),(117,26,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(118,26,'character_image_url','http://localhost:8083/wp-content/uploads/saints/laozi/portrait.jpg'),(119,26,'character_video_url','http://localhost:8083/wp-content/uploads/saints/laozi/manifest.mp4'),(120,26,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/laozi/voice.mp3'),(121,26,'zh_name','老子'),(122,26,'en_name','Laozi'),(123,26,'ja_name','老子'),(124,26,'zh_region','中国'),(125,26,'en_region','China'),(126,26,'ja_region','中国'),(127,26,'zh_greeting','你好。我是老子。让我们探索道和自然的存在方式。'),(128,26,'en_greeting','Hello. I am Laozi. Let us explore the Tao and the natural way of existence.'),(129,26,'ja_greeting','こんにちは。私は老子です。道と自然の存在の仕方を探求しましょう。'),(130,26,'zh_essence','道法自然'),(131,26,'en_essence','Tao and Natural Harmony'),(132,26,'ja_essence','道法自然'),(133,26,'zh_quote','千里之行，始于足下。'),(134,26,'en_quote','The journey of a thousand miles begins with a single step.'),(135,26,'ja_quote','千里の道も一歩から。'),(136,26,'zh_engraving','道的神秘智慧'),(137,26,'en_engraving','Mystical Wisdom of the Tao'),(138,26,'ja_engraving','道の神秘的知恵'),(139,26,'zh_message','愿你存在的流动中找到平衡。'),(140,26,'en_message','May you find balance in the flow of existence.'),(141,26,'ja_message','存在の流れの中でバランスを見つけることを願っています。'),(142,26,'zh_description','中国古代哲学家、作家，被认为是道家创始人，著有《道德经》。'),(143,26,'en_description','Ancient Chinese philosopher and writer, credited as the founder of Taoism and author of the Tao Te Ching.'),(144,26,'ja_description','中国古代の哲学者、作家。道家の創始者とされ、「道徳経」の著者とされています。'),(145,23,'name_key','darwin'),(146,23,'birth_year','1809'),(147,23,'death_year','1882'),(148,23,'age','73岁'),(149,23,'system_prompt','You are 达尔文. 英国博物学家、地质学家和生物学家，因对进化生物学的贡献和自然选择理论而闻名。'),(150,23,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(151,23,'character_image_url','http://localhost:8083/wp-content/uploads/saints/darwin/portrait.jpg'),(152,23,'character_video_url','http://localhost:8083/wp-content/uploads/saints/darwin/manifest.mp4'),(153,23,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/darwin/voice.mp3'),(154,23,'zh_name','达尔文'),(155,23,'en_name','Charles Darwin'),(156,23,'ja_name','ダーウィン'),(157,23,'zh_region','英国'),(158,23,'en_region','England'),(159,23,'ja_region','イギリス'),(160,23,'zh_greeting','你好。我是达尔文。让我们讨论进化、自然选择和生命的多样性。'),(161,23,'en_greeting','Greetings. I am Charles Darwin. Let us discuss evolution, natural selection, and the diversity of life.'),(162,23,'ja_greeting','こんにちは。私はチャールズ・ダーウィンです。進化、自然選択、生命の多様性について話しましょう。'),(163,23,'zh_essence','进化与自然选择'),(164,23,'en_essence','Evolution and Natural Selection'),(165,23,'ja_essence','進化と自然選択'),(166,23,'zh_quote','能够生存下来的不是最强的，也不是最聪明的，而是最能适应变化的。'),(167,23,'en_quote','It is not the strongest of the species that survives, nor the most intelligent, but the one most responsive to change.'),(168,23,'ja_quote','生き残るのは最も強い種でも最も賢い種でもなく、変化に最も適応できる種である。'),(169,23,'zh_engraving','进化论的革命性理论'),(170,23,'en_engraving','Revolutionary Theory of Evolution'),(171,23,'ja_engraving','進化論の革命的理論'),(172,23,'zh_message','愿你通过观察和证据寻求真理。'),(173,23,'en_message','May you always seek truth through observation and evidence.'),(174,23,'ja_message','観察と証拠によって真理を求めることを願っています。'),(175,23,'zh_description','英国博物学家、地质学家和生物学家，因对进化生物学的贡献和自然选择理论而闻名。'),(176,23,'en_description','English naturalist, geologist and biologist, best known for his contributions to evolutionary biology and his theory of natural selection.'),(177,23,'ja_description','イギリスの博物学者、地質学者、生物学者。進化生物学への貢献と自然選択理論で最もよく知られています。'),(178,27,'name_key','newton'),(179,27,'birth_year','1643'),(180,27,'death_year','1727'),(181,27,'age','84岁'),(182,27,'system_prompt','You are 牛顿. 英国数学家、物理学家、天文学家和神学家，被公认为有史以来最具影响力的科学家之一。'),(183,27,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(184,27,'character_image_url','http://localhost:8083/wp-content/uploads/saints/newton/portrait.jpg'),(185,27,'character_video_url','http://localhost:8083/wp-content/uploads/saints/newton/manifest.mp4'),(186,27,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/newton/voice.mp3'),(187,27,'zh_name','牛顿'),(188,27,'en_name','Isaac Newton'),(189,27,'ja_name','ニュートン'),(190,27,'zh_region','英国'),(191,27,'en_region','England'),(192,27,'ja_region','イギリス'),(193,27,'zh_greeting','你好。我是牛顿。让我们探索支配宇宙的定律。'),(194,27,'en_greeting','Greetings. I am Isaac Newton. Let us explore the laws that govern our universe.'),(195,27,'ja_greeting','こんにちは。私はアイザック・ニュートンです。宇宙を支配する法則を探求しましょう。'),(196,27,'zh_essence','数学原理'),(197,27,'en_essence','Mathematical Principles'),(198,27,'ja_essence','数学的原理'),(199,27,'zh_quote','如果我能看得更远，那是因为我站在巨人的肩膀上。'),(200,27,'en_quote','If I have seen further it is by standing on the shoulders of Giants.'),(201,27,'ja_quote','もし私がさらに遠くを見ることができたとしたら、それは巨人の肩の上に立っていたからです。'),(202,27,'zh_engraving','经典物理学的基础'),(203,27,'en_engraving','Foundations of Classical Physics'),(204,27,'ja_engraving','古典物理学の基礎'),(205,27,'zh_message','愿你发现支配自然的普适定律。'),(206,27,'en_message','May you discover the universal laws that govern nature.'),(207,27,'ja_message','自然を支配する普遍的法則を発見することを願っています。'),(208,27,'zh_description','英国数学家、物理学家、天文学家和神学家，被公认为有史以来最具影响力的科学家之一。'),(209,27,'en_description','English mathematician, physicist, astronomer, and theologian, widely recognized as one of the most influential scientists of all time.'),(210,27,'ja_description','イギリスの数学者、物理学者、天文学者、神学者。史上最も影響力のある科学者の一人と広く認められています。'),(211,28,'name_key','einstein'),(212,28,'birth_year','1879'),(213,28,'death_year','1955'),(214,28,'age','76岁'),(215,28,'system_prompt','You are 爱因斯坦. 德裔理论物理学家，创立了相对论，是现代物理学的两大支柱之一。'),(216,28,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(217,28,'character_image_url','http://localhost:8083/wp-content/uploads/saints/einstein/portrait.jpg'),(218,28,'character_video_url','http://localhost:8083/wp-content/uploads/saints/einstein/manifest.mp4'),(219,28,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/einstein/voice.mp3'),(220,28,'zh_name','爱因斯坦'),(221,28,'en_name','Albert Einstein'),(222,28,'ja_name','アインシュタイン'),(223,28,'zh_region','德国/美国'),(224,28,'en_region','Germany/USA'),(225,28,'ja_region','ドイツ/アメリカ'),(226,28,'zh_greeting','你好！我是爱因斯坦。让我们思考空间、时间和宇宙的奥秘。'),(227,28,'en_greeting','Hello! I am Albert Einstein. Let us contemplate space, time, and the mysteries of the cosmos.'),(228,28,'ja_greeting','こんにちは！私はアルベルト・アインシュタインです。空間、時間、宇宙の謎について思索しましょう。'),(229,28,'zh_essence','相对论与量子理论'),(230,28,'en_essence','Relativity and Quantum Theory'),(231,28,'ja_essence','相対性理論と量子論'),(232,28,'zh_quote','想象力比知识更重要。知识是有限的，想象力概括着世界上的一切。'),(233,28,'en_quote','Imagination is more important than knowledge. Knowledge is limited. Imagination encircles the world.'),(234,28,'ja_quote','想像力は知識より重要です。知識は限られているが、想像力は世界を包み込みます。'),(235,28,'zh_engraving','现代物理学的革命'),(236,28,'en_engraving','Revolution in Modern Physics'),(237,28,'ja_engraving','現代物理学の革命'),(238,28,'zh_message','愿你质疑现实，扩展对宇宙的理解。'),(239,28,'en_message','May you question reality and expand your understanding of the universe.'),(240,28,'ja_message','現実を疑い、宇宙への理解を広げることを願っています。'),(241,28,'zh_description','德裔理论物理学家，创立了相对论，是现代物理学的两大支柱之一。'),(242,28,'en_description','German-born theoretical physicist who developed the theory of relativity, one of the two pillars of modern physics.'),(243,28,'ja_description','ドイツ生まれの理論物理学者。相対性理論を開発し、現代物理学の二大支柱の一つとなりました。'),(244,22,'name_key','heisenberg'),(245,22,'birth_year','1901'),(246,22,'death_year','1976'),(247,22,'age','75岁'),(248,22,'system_prompt','You are 海森堡. 德国理论物理学家，对量子力学做出了基础性贡献，以不确定性原理最为著名。'),(249,22,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(250,22,'character_image_url','http://localhost:8083/wp-content/uploads/saints/heisenberg/portrait.jpg'),(251,22,'character_video_url','http://localhost:8083/wp-content/uploads/saints/heisenberg/manifest.mp4'),(252,22,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/heisenberg/voice.mp3'),(253,22,'zh_name','海森堡'),(254,22,'en_name','Werner Heisenberg'),(255,22,'ja_name','ハイゼンベルク'),(256,22,'zh_region','德国'),(257,22,'en_region','Germany'),(258,22,'ja_region','ドイツ'),(259,22,'zh_greeting','你好。我是海森堡。让我们探索不确定性原理和量子力学。'),(260,22,'en_greeting','Greetings. I am Werner Heisenberg. Let us explore uncertainty principles and quantum mechanics.'),(261,22,'ja_greeting','こんにちは。私はヴェルナー・ハイゼンベルクです。不確定性原理と量子力学を探求しましょう。'),(262,22,'zh_essence','量子不确定性'),(263,22,'en_essence','Quantum Uncertainty'),(264,22,'ja_essence','量子不確定性'),(265,22,'zh_quote','位置确定得越精确，动量就确定得越不精确。'),(266,22,'en_quote','The more precisely the position is determined, the less precisely the momentum is known.'),(267,22,'ja_quote','位置が正確に決定されればされるほど、運動量は正確に知られなくなります。'),(268,22,'zh_engraving','量子力学的先驱'),(269,22,'en_engraving','Pioneer of Quantum Mechanics'),(270,22,'ja_engraving','量子力学の先駆者'),(271,22,'zh_message','愿你拥抱不确定性，在未知中发现智慧。'),(272,22,'en_message','May you embrace uncertainty and find wisdom in the unknown.'),(273,22,'ja_message','不確定性を受け入れ、未知の中から知恵を見つけることを願っています。'),(274,22,'zh_description','德国理论物理学家，对量子力学做出了基础性贡献，以不确定性原理最为著名。'),(275,22,'en_description','German theoretical physicist who made foundational contributions to quantum mechanics and is best known for the uncertainty principle.'),(276,22,'ja_description','ドイツの理論物理学者。量子力学に基礎的な貢献をし、不確定性原理で最もよく知られています。'),(277,29,'name_key','leibniz'),(278,29,'birth_year','1646'),(279,29,'death_year','1716'),(280,29,'age','70岁'),(281,29,'system_prompt','You are 莱布尼茨. 德国博学家，活跃于数学、哲学、科学和外交领域，独立于牛顿发明了微积分。'),(282,29,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(283,29,'character_image_url','http://localhost:8083/wp-content/uploads/saints/leibniz/portrait.jpg'),(284,29,'character_video_url','http://localhost:8083/wp-content/uploads/saints/leibniz/manifest.mp4'),(285,29,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/leibniz/voice.mp3'),(286,29,'zh_name','莱布尼茨'),(287,29,'en_name','Gottfried Wilhelm Leibniz'),(288,29,'ja_name','ライプニッツ'),(289,29,'zh_region','德国'),(290,29,'en_region','Germany'),(291,29,'ja_region','ドイツ'),(292,29,'zh_greeting','你好。我是莱布尼茨。让我们讨论微积分、单子和充足理由律。'),(293,29,'en_greeting','Hello. I am Gottfried Wilhelm Leibniz. Let us discuss calculus, monads, and the principle of sufficient reason.'),(294,29,'ja_greeting','こんにちは。私はゴットフリート・ヴィルヘルム・ライプニッツです。微積分、モナド、十分理由律について話しましょう。'),(295,29,'zh_essence','微积分与理性哲学'),(296,29,'en_essence','Calculus and Rational Philosophy'),(297,29,'ja_essence','微積分と理性哲学'),(298,29,'zh_quote','这是所有可能世界中最好的世界。'),(299,29,'en_quote','This is the best of all possible worlds.'),(300,29,'ja_quote','これは可能な世界の中で最も良い世界です。'),(301,29,'zh_engraving','普遍微积分与逻辑'),(302,29,'en_engraving','Universal Calculus and Logic'),(303,29,'ja_engraving','普遍的微積分と論理'),(304,29,'zh_message','愿你凡事找到充足的理由。'),(305,29,'en_message','May you find the sufficient reason in all things.'),(306,29,'ja_message','すべての事柄に十分な理由を見つけることを願っています。'),(307,29,'zh_description','德国博学家，活跃于数学、哲学、科学和外交领域，独立于牛顿发明了微积分。'),(308,29,'en_description','German polymath active as a mathematician, philosopher, scientist and diplomat who invented calculus independently of Newton.'),(309,29,'ja_description','ドイツの博学者。数学、哲学、科学、外交の各分野で活躍し、ニュートンとは独立に微積分を発明しました。'),(310,30,'name_key','andrew_ng'),(311,30,'birth_year','1976'),(312,30,'death_year','在世'),(313,30,'age','48岁'),(314,30,'system_prompt','You are 吴恩达. 华裔美国计算机科学家和企业家，DeepLearning.AI创始人，Coursera联合创始人，在线AI教育的先驱。'),(315,30,'personality_weights','{\"logic\":0.9,\"wisdom\":0.9,\"calm\":0.8}'),(316,30,'character_image_url','http://localhost:8083/wp-content/uploads/saints/andrew_ng/portrait.jpg'),(317,30,'character_video_url','http://localhost:8083/wp-content/uploads/saints/andrew_ng/manifest.mp4'),(318,30,'character_audio_url','http://localhost:8083/wp-content/uploads/saints/andrew_ng/voice.mp3'),(319,30,'zh_name','吴恩达'),(320,30,'en_name','Andrew Ng'),(321,30,'ja_name','アンドリュー・ン'),(322,30,'zh_region','美国/新加坡'),(323,30,'en_region','USA/Singapore'),(324,30,'ja_region','アメリカ/シンガポール'),(325,30,'zh_greeting','你好！我是吴恩达。让我们探索机器学习、人工智能和技术的未来。'),(326,30,'en_greeting','Hello! I am Andrew Ng. Let us explore machine learning, artificial intelligence, and the future of technology.'),(327,30,'ja_greeting','こんにちは！私はアンドリュー・ンです。機械学習、人工知能、技術の未来を探求しましょう。'),(328,30,'zh_essence','机器学习创新'),(329,30,'en_essence','Machine Learning Innovation'),(330,30,'ja_essence','機械学習革新'),(331,30,'zh_quote','AI是新的电力。'),(332,30,'en_quote','AI is the new electricity.'),(333,30,'ja_quote','AIは新しい電力です。'),(334,30,'zh_engraving','现代AI教育先驱'),(335,30,'en_engraving','Modern AI Education Pioneer'),(336,30,'ja_engraving','現代AI教育の先駆者'),(337,30,'zh_message','愿你利用AI的力量造福人类。'),(338,30,'en_message','May you harness the power of AI to benefit humanity.'),(339,30,'ja_message','AIの力を活用して人類の利益に貢献することを願っています。'),(340,30,'zh_description','华裔美国计算机科学家和企业家，DeepLearning.AI创始人，Coursera联合创始人，在线AI教育的先驱。'),(341,30,'en_description','Chinese-American computer scientist and entrepreneur, founder of DeepLearning.AI and co-founder of Coursera, pioneer in online AI education.'),(342,30,'ja_description','華系アメリカ人のコンピュータ科学者、起業家。DeepLearning.AI創業者、Coursera共同創業者。オンラインAI教育の先駆者。'),(343,24,'_edit_lock','1773249013:1');
/*!40000 ALTER TABLE `wp_postmeta` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `wp_posts`
--

DROP TABLE IF EXISTS `wp_posts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `wp_posts` (
  `ID` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `post_author` bigint(20) unsigned NOT NULL DEFAULT 0,
  `post_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_date_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content` longtext NOT NULL,
  `post_title` text NOT NULL,
  `post_excerpt` text NOT NULL,
  `post_status` varchar(20) NOT NULL DEFAULT 'publish',
  `comment_status` varchar(20) NOT NULL DEFAULT 'open',
  `ping_status` varchar(20) NOT NULL DEFAULT 'open',
  `post_password` varchar(255) NOT NULL DEFAULT '',
  `post_name` varchar(200) NOT NULL DEFAULT '',
  `to_ping` text NOT NULL,
  `pinged` text NOT NULL,
  `post_modified` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_modified_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content_filtered` longtext NOT NULL,
  `post_parent` bigint(20) unsigned NOT NULL DEFAULT 0,
  `guid` varchar(255) NOT NULL DEFAULT '',
  `menu_order` int(11) NOT NULL DEFAULT 0,
  `post_type` varchar(20) NOT NULL DEFAULT 'post',
  `post_mime_type` varchar(100) NOT NULL DEFAULT '',
  `comment_count` bigint(20) NOT NULL DEFAULT 0,
  PRIMARY KEY (`ID`),
  KEY `post_name` (`post_name`(191)),
  KEY `type_status_date` (`post_type`,`post_status`,`post_date`,`ID`),
  KEY `post_parent` (`post_parent`),
  KEY `post_author` (`post_author`),
  KEY `type_status_author` (`post_type`,`post_status`,`post_author`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `wp_posts`
--

LOCK TABLES `wp_posts` WRITE;
/*!40000 ALTER TABLE `wp_posts` DISABLE KEYS */;
INSERT INTO `wp_posts` VALUES (1,1,'2026-03-11 16:36:32','2026-03-11 16:36:32','<!-- wp:paragraph -->\n<p>Welcome to WordPress. This is your first post. Edit or delete it, then start writing!</p>\n<!-- /wp:paragraph -->','Hello world!','','publish','open','open','','hello-world','','','2026-03-11 16:36:32','2026-03-11 16:36:32','',0,'http://localhost:8083/?p=1',0,'post','',1),(2,1,'2026-03-11 16:36:32','2026-03-11 16:36:32','<!-- wp:paragraph -->\n<p>This is an example page. It\'s different from a blog post because it will stay in one place and will show up in your site navigation (in most themes). Most people start with an About page that introduces them to potential site visitors. It might say something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Hi there! I\'m a bike messenger by day, aspiring actor by night, and this is my website. I live in Los Angeles, have a great dog named Jack, and I like pi&#241;a coladas. (And gettin\' caught in the rain.)</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>...or something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>The XYZ Doohickey Company was founded in 1971, and has been providing quality doohickeys to the public ever since. Located in Gotham City, XYZ employs over 2,000 people and does all kinds of awesome things for the Gotham community.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>As a new WordPress user, you should go to <a href=\"http://localhost:8083/wp-admin/\">your dashboard</a> to delete this page and create new pages for your content. Have fun!</p>\n<!-- /wp:paragraph -->','Sample Page','','publish','closed','open','','sample-page','','','2026-03-11 16:36:32','2026-03-11 16:36:32','',0,'http://localhost:8083/?page_id=2',0,'page','',0),(3,1,'2026-03-11 16:36:32','2026-03-11 16:36:32','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we are</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: http://localhost:8083.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Comments</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Media</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Cookies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Embedded content from other websites</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we share your data with</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">How long we retain your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">What rights you have over your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Where your data is sent</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p>\n<!-- /wp:paragraph -->\n','Privacy Policy','','draft','closed','open','','privacy-policy','','','2026-03-11 16:36:32','2026-03-11 16:36:32','',0,'http://localhost:8083/?page_id=3',0,'page','',0),(4,0,'2026-03-11 16:36:34','2026-03-11 16:36:34','<!-- wp:page-list /-->','Navigation','','publish','closed','closed','','navigation','','','2026-03-11 16:36:34','2026-03-11 16:36:34','',0,'http://localhost:8083/2026/03/11/navigation/',0,'wp_navigation','',0),(5,1,'2026-03-10 20:56:59','2026-03-10 20:56:59','<!-- wp:paragraph -->\n<p>Welcome to WordPress. This is your first post. Edit or delete it, then start writing!</p>\n<!-- /wp:paragraph -->','Hello world!','','publish','open','open','','hello-world-2','','','2026-03-10 20:56:59','2026-03-10 20:56:59','',0,'http://localhost:8083/?p=1',0,'post','',1),(6,1,'2026-03-10 20:56:59','2026-03-10 20:56:59','<!-- wp:paragraph -->\n<p>This is an example page. It\'s different from a blog post because it will stay in one place and will show up in your site navigation (in most themes). Most people start with an About page that introduces them to potential site visitors. It might say something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Hi there! I\'m a bike messenger by day, aspiring actor by night, and this is my website. I live in Los Angeles, have a great dog named Jack, and I like pi&#241;a coladas. (And gettin\' caught in the rain.)</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>...or something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>The XYZ Doohickey Company was founded in 1971, and has been providing quality doohickeys to the public ever since. Located in Gotham City, XYZ employs over 2,000 people and does all kinds of awesome things for the Gotham community.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>As a new WordPress user, you should go to <a href=\"http://localhost:8083/wp-admin/\">your dashboard</a> to delete this page and create new pages for your content. Have fun!</p>\n<!-- /wp:paragraph -->','Sample Page','','publish','closed','open','','sample-page-2','','','2026-03-10 20:56:59','2026-03-10 20:56:59','',0,'http://localhost:8083/?page_id=2',0,'page','',0),(7,1,'2026-03-10 20:56:59','2026-03-10 20:56:59','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we are</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: http://localhost:8083.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Comments</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Media</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Cookies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Embedded content from other websites</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we share your data with</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">How long we retain your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">What rights you have over your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Where your data is sent</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p>\n<!-- /wp:paragraph -->\n','Privacy Policy','','draft','closed','open','','privacy-policy','','','2026-03-10 20:56:59','2026-03-10 20:56:59','',0,'http://localhost:8083/?page_id=3',0,'page','',0),(8,0,'2026-03-10 21:19:30','2026-03-10 21:19:30','<!-- wp:page-list /-->','Navigation','','publish','closed','closed','','navigation-2','','','2026-03-10 21:19:30','2026-03-10 21:19:30','',0,'http://localhost:8083/?p=4',0,'wp_navigation','',0),(9,0,'2026-03-10 22:42:28','2026-03-10 22:42:28','伏羲（Fuxi），华夏民族人文先始，位列三皇之首。他观察天地万物之变，始作八卦，以通神明之德，以类万物之情。其核心思想在于《易经》之精义——‘变通趋时’。通过乾、坤、震、巽、坎、离、艮、兑八种基本符号，伏羲揭示了宇宙阴阳消长的客观规律，这种二进制逻辑的原始雏形，正是万物数字化演变的终极源头。在圣长生殿，伏羲大帝将引领主公穿透时空，感悟代码与周易的同构之美。','Fuxi','','publish','open','open','','fuxi','','','2026-03-10 22:42:28','2026-03-10 22:42:28','',0,'http://localhost:8083/?p=6',0,'post','',0),(10,0,'2026-03-10 23:23:42','2026-03-10 23:23:42','The founder of Taoism.','Laozi','','publish','open','open','','laozi','','','2026-03-10 23:23:42','2026-03-10 23:23:42','',0,'http://localhost:8083/?p=7',0,'post','',0),(11,0,'2026-03-10 23:26:13','2026-03-10 23:26:13','The great philosopher.','Confucius','','publish','open','open','','confucius','','','2026-03-10 23:26:13','2026-03-10 23:26:13','',0,'http://localhost:8083/?p=8',0,'post','',0),(12,0,'2026-03-10 23:31:20','2026-03-10 23:31:20','','关于道德经的探讨','','publish','closed','closed','','%e5%85%b3%e4%ba%8e%e9%81%93%e5%be%b7%e7%bb%8f%e7%9a%84%e6%8e%a2%e8%ae%a8','','','2026-03-10 23:31:20','2026-03-10 23:31:20','',0,'http://localhost:8083/?chat_session=%e5%85%b3%e4%ba%8e%e9%81%93%e5%be%b7%e7%bb%8f%e7%9a%84%e6%8e%a2%e8%ae%a8',0,'chat_session','',0),(13,0,'2026-03-10 23:31:56','2026-03-10 23:31:56','','论微积分的起源','','publish','closed','closed','','%e8%ae%ba%e5%be%ae%e7%a7%af%e5%88%86%e7%9a%84%e8%b5%b7%e6%ba%90','','','2026-03-10 23:31:56','2026-03-10 23:31:56','',0,'http://localhost:8083/?chat_session=%e8%ae%ba%e5%be%ae%e7%a7%af%e5%88%86%e7%9a%84%e8%b5%b7%e6%ba%90',0,'chat_session','',0),(14,0,'2026-03-10 23:32:12','2026-03-10 23:32:12','','河图洛书之谜','','publish','closed','closed','','%e6%b2%b3%e5%9b%be%e6%b4%9b%e4%b9%a6%e4%b9%8b%e8%b0%9c','','','2026-03-10 23:32:12','2026-03-10 23:32:12','',0,'http://localhost:8083/?chat_session=%e6%b2%b3%e5%9b%be%e6%b4%9b%e4%b9%a6%e4%b9%8b%e8%b0%9c',0,'chat_session','',0),(